describe('truncateContent', () => {
  it('should handle happy path - normal truncation', () => {
    const content = 'Hello world! This is a test string that should be truncated properly.';
    const result = truncateContent(content, 20);
    expect(result).toBe('Hello world! This is…');
  });

  it('should handle edge case - content shorter than maxLength', () => {
    const content = 'Short text';
    const result = truncateContent(content, 20);
    expect(result).toBe('Short text');
  });

  it('should handle null/empty - null input', () => {
    const result = truncateContent(null as any, 20);
    expect(result).toBe('');
  });

  it('should handle null/empty - undefined input', () => {
    const result = truncateContent(undefined as any, 20);
    expect(result).toBe('');
  });

  it('should handle null/empty - empty string input', () => {
    const result = truncateContent('', 20);
    expect(result).toBe('');
  });

  it('should handle null/empty - zero maxLength', () => {
    const content = 'Any content';
    const result = truncateContent(content, 0);
    expect(result).toBe('');
  });
});

